/**
 * Preferences validation — pure functions for notification preference checks.
 *
 * Extracted from PreferencesService to enable reuse and independent testing.
 * No side effects, no database calls.
 *
 * Supports per-channel checks: email, SMS, and webhook.
 */

import type { NotificationType } from '../models/notification.js';
import type { NotificationChannel } from '../models/notification.js';
import type { UserPreferences, NotificationCategory } from '../models/user-preferences.js';
import { notificationTypeToCategory } from '../models/user-preferences.js';

/**
 * Determine whether an email notification should be sent based on user preferences.
 *
 * Returns true if:
 * - No preferences exist (null/undefined — default: send all)
 * - Email is enabled AND frequency is not 'none' AND the notification's
 *   category is in the user's subscribed categories
 */
export function shouldSendEmail(
  prefs: UserPreferences | null | undefined,
  notificationType: NotificationType,
): boolean {
  // No preferences stored — default to sending
  if (!prefs) {
    return true;
  }

  if (!prefs.email.enabled) {
    return false;
  }

  if (prefs.email.frequency === 'none') {
    return false;
  }

  const category: NotificationCategory = notificationTypeToCategory[notificationType];
  if (!prefs.email.subscribedCategories.includes(category)) {
    return false;
  }

  return true;
}

/**
 * Determine whether an SMS notification should be sent based on user preferences.
 *
 * Returns true if:
 * - No preferences exist (null/undefined — default: do NOT send, SMS is opt-in)
 * - SMS is enabled AND the notification's category is in subscribed categories
 */
export function shouldSendSms(
  prefs: UserPreferences | null | undefined,
  notificationType: NotificationType,
): boolean {
  // No preferences stored — SMS defaults to disabled (opt-in)
  if (!prefs) {
    return false;
  }

  if (!prefs.sms.enabled) {
    return false;
  }

  const category: NotificationCategory = notificationTypeToCategory[notificationType];
  if (!prefs.sms.subscribedCategories.includes(category)) {
    return false;
  }

  return true;
}

/**
 * Determine whether a webhook notification should be sent based on user preferences.
 *
 * Returns true if:
 * - No preferences exist (null/undefined — default: do NOT send, webhook is opt-in)
 * - Webhook is enabled AND the notification's category is in subscribed categories
 */
export function shouldSendWebhook(
  prefs: UserPreferences | null | undefined,
  notificationType: NotificationType,
): boolean {
  // No preferences stored — webhook defaults to disabled (opt-in)
  if (!prefs) {
    return false;
  }

  if (!prefs.webhook.enabled) {
    return false;
  }

  const category: NotificationCategory = notificationTypeToCategory[notificationType];
  if (!prefs.webhook.subscribedCategories.includes(category)) {
    return false;
  }

  return true;
}

/**
 * Generic channel-based preference check.
 * Dispatches to the appropriate per-channel function.
 */
export function shouldSendToChannel(
  prefs: UserPreferences | null | undefined,
  channel: NotificationChannel,
  notificationType: NotificationType,
): boolean {
  switch (channel) {
    case 'email':
      return shouldSendEmail(prefs, notificationType);
    case 'sms':
      return shouldSendSms(prefs, notificationType);
    case 'webhook':
      return shouldSendWebhook(prefs, notificationType);
    default:
      // Channels without preference support (e.g. 'in-app') — allow by default
      return true;
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user preferences and methods to check
 * whether a notification should be sent based on user settings.
 * Supports per-channel preferences: email, SMS, and webhook.
 *
 * Depends on:
 * - PreferencesRepository for data access
 * - UserPreferences model for types and defaults
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
} from '../models/user-preferences.js';
import {
  getDefaultUserPreferences,
  getDefaultEmailPreferences,
  getDefaultSmsPreferences,
  getDefaultWebhookPreferences,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';
import { shouldSendEmail as checkShouldSendEmail, shouldSendToChannel as checkShouldSendToChannel } from '../validators/preferences.validator.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns defaults if none exist.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return getDefaultUserPreferences(userId);
  }

  /**
   * Create preferences for a user.
   * Throws if preferences already exist for this user.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const emailDefaults = getDefaultEmailPreferences();
    const emailPrefs = input.email
      ? {
          enabled: input.email.enabled ?? emailDefaults.enabled,
          frequency: input.email.frequency ?? emailDefaults.frequency,
          subscribedCategories: input.email.subscribedCategories ?? [...emailDefaults.subscribedCategories],
        }
      : emailDefaults;

    const smsDefaults = getDefaultSmsPreferences();
    const smsPrefs = input.sms
      ? {
          enabled: input.sms.enabled ?? smsDefaults.enabled,
          subscribedCategories: input.sms.subscribedCategories ?? [...smsDefaults.subscribedCategories],
        }
      : smsDefaults;

    const webhookDefaults = getDefaultWebhookPreferences();
    const webhookPrefs = input.webhook
      ? {
          enabled: input.webhook.enabled ?? webhookDefaults.enabled,
          subscribedCategories: input.webhook.subscribedCategories ?? [...webhookDefaults.subscribedCategories],
        }
      : webhookDefaults;

    const prefs: UserPreferences = {
      id: `prefs-${input.userId}`,
      userId: input.userId,
      email: emailPrefs,
      sms: smsPrefs,
      webhook: webhookPrefs,
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    this.logger.info(`Creating preferences for user: ${input.userId}`);
    return this.repository.save(prefs);
  }

  /**
   * Update preferences for a user.
   * Throws if no preferences exist for this user.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      throw new Error(`No preferences found for user: ${userId}`);
    }

    const updatedEmail = input.email
      ? {
          enabled: input.email.enabled ?? existing.email.enabled,
          frequency: input.email.frequency ?? existing.email.frequency,
          subscribedCategories: input.email.subscribedCategories ?? [...existing.email.subscribedCategories],
        }
      : existing.email;

    const updatedSms = input.sms
      ? {
          enabled: input.sms.enabled ?? existing.sms.enabled,
          subscribedCategories: input.sms.subscribedCategories ?? [...existing.sms.subscribedCategories],
        }
      : existing.sms;

    const updatedWebhook = input.webhook
      ? {
          enabled: input.webhook.enabled ?? existing.webhook.enabled,
          subscribedCategories: input.webhook.subscribedCategories ?? [...existing.webhook.subscribedCategories],
        }
      : existing.webhook;

    const updated: UserPreferences = {
      ...existing,
      email: updatedEmail,
      sms: updatedSms,
      webhook: updatedWebhook,
      updatedAt: new Date(),
    };

    this.logger.info(`Updating preferences for user: ${userId}`);
    return this.repository.update(existing.id, updated);
  }

  /**
   * Delete preferences for a user (resets to defaults).
   */
  deletePreferences(userId: string): boolean {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      return false;
    }
    this.logger.info(`Deleting preferences for user: ${userId}`);
    return this.repository.delete(existing.id);
  }

  /**
   * Check whether a notification should be sent to a user via email.
   * Delegates to the pure validator function, passing in the stored preferences.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);
    return checkShouldSendEmail(prefs, notificationType);
  }

  /**
   * Check whether a notification should be sent to a user via a specific channel.
   * Generic method that dispatches to the appropriate per-channel check.
   */
  shouldSendToChannel(userId: string, channel: NotificationChannel, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);
    return checkShouldSendToChannel(prefs, channel, notificationType);
  }
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Depends on the Database utility layer for storage.
 *
 * Stores per-channel preferences (email, SMS, webhook) as flattened fields.
 * Backward compatible: missing SMS/webhook fields default to disabled.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, NotificationCategory } from '../models/user-preferences.js';
import { getDefaultSmsPreferences, getDefaultWebhookPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    // Backward compatible: if SMS/webhook fields are missing, use defaults (disabled)
    const smsDefaults = getDefaultSmsPreferences();
    const webhookDefaults = getDefaultWebhookPreferences();

    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as UserPreferences['email']['frequency'],
        subscribedCategories: JSON.parse(record['emailSubscribedCategories'] as string) as NotificationCategory[],
      },
      sms: {
        enabled: record['smsEnabled'] != null ? record['smsEnabled'] as boolean : smsDefaults.enabled,
        subscribedCategories: record['smsSubscribedCategories'] != null
          ? JSON.parse(record['smsSubscribedCategories'] as string) as NotificationCategory[]
          : [...smsDefaults.subscribedCategories],
      },
      webhook: {
        enabled: record['webhookEnabled'] != null ? record['webhookEnabled'] as boolean : webhookDefaults.enabled,
        subscribedCategories: record['webhookSubscribedCategories'] != null
          ? JSON.parse(record['webhookSubscribedCategories'] as string) as NotificationCategory[]
          : [...webhookDefaults.subscribedCategories],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedCategories: JSON.stringify(entity.email.subscribedCategories),
      smsEnabled: entity.sms.enabled,
      smsSubscribedCategories: JSON.stringify(entity.sms.subscribedCategories),
      webhookEnabled: entity.webhook.enabled,
      webhookSubscribedCategories: JSON.stringify(entity.webhook.subscribedCategories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

