import { describe, it, expect } from 'vitest';
import { shouldSendEmail, shouldSendSms, shouldSendWebhook, shouldSendToChannel } from '../../src/validators/preferences.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';

function makePrefs(overrides?: {
  email?: Partial<UserPreferences['email']>;
  sms?: Partial<UserPreferences['sms']>;
  webhook?: Partial<UserPreferences['webhook']>;
}): UserPreferences {
  return {
    id: 'prefs-user-1',
    userId: 'user-1',
    email: {
      enabled: true,
      frequency: 'immediate',
      subscribedCategories: ['order-updates', 'account'],
      ...overrides?.email,
    },
    sms: {
      enabled: false,
      subscribedCategories: ['order-updates', 'account'],
      ...overrides?.sms,
    },
    webhook: {
      enabled: false,
      subscribedCategories: ['order-updates', 'account'],
      ...overrides?.webhook,
    },
    createdAt: new Date(),
    updatedAt: new Date(),
  };
}

describe('Preferences Validators', () => {
  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (null)', () => {
      expect(shouldSendEmail(null, 'order-confirmation')).toBe(true);
    });

    it('should return true when no preferences exist (undefined)', () => {
      expect(shouldSendEmail(undefined, 'order-confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      const prefs = makePrefs();
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(true);
      expect(shouldSendEmail(prefs, 'order-status-update')).toBe(true);
      expect(shouldSendEmail(prefs, 'welcome')).toBe(true);
      expect(shouldSendEmail(prefs, 'user-updated')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      const prefs = makePrefs({ email: { enabled: false } });
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(false);
    });

    it('should return false when frequency is none', () => {
      const prefs = makePrefs({ email: { frequency: 'none' } });
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      const prefs = makePrefs({ email: { subscribedCategories: ['account'] } });
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(false);
    });

    it('should return true for subscribed category only', () => {
      const prefs = makePrefs({ email: { subscribedCategories: ['order-updates'] } });
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(true);
      expect(shouldSendEmail(prefs, 'welcome')).toBe(false);
    });

    it('should work with daily-digest frequency', () => {
      const prefs = makePrefs({ email: { frequency: 'daily-digest' } });
      expect(shouldSendEmail(prefs, 'order-confirmation')).toBe(true);
    });

    it('should work with weekly-digest frequency', () => {
      const prefs = makePrefs({ email: { frequency: 'weekly-digest' } });
      expect(shouldSendEmail(prefs, 'welcome')).toBe(true);
    });
  });

  describe('shouldSendSms', () => {
    it('should return false when no preferences exist (opt-in channel)', () => {
      expect(shouldSendSms(null, 'order-confirmation')).toBe(false);
      expect(shouldSendSms(undefined, 'order-confirmation')).toBe(false);
    });

    it('should return false when SMS is disabled', () => {
      const prefs = makePrefs({ sms: { enabled: false } });
      expect(shouldSendSms(prefs, 'order-confirmation')).toBe(false);
    });

    it('should return true when SMS is enabled and category is subscribed', () => {
      const prefs = makePrefs({ sms: { enabled: true } });
      expect(shouldSendSms(prefs, 'order-confirmation')).toBe(true);
      expect(shouldSendSms(prefs, 'welcome')).toBe(true);
    });

    it('should return false when category is not subscribed', () => {
      const prefs = makePrefs({ sms: { enabled: true, subscribedCategories: ['account'] } });
      expect(shouldSendSms(prefs, 'order-confirmation')).toBe(false);
      expect(shouldSendSms(prefs, 'welcome')).toBe(true);
    });
  });

  describe('shouldSendWebhook', () => {
    it('should return false when no preferences exist (opt-in channel)', () => {
      expect(shouldSendWebhook(null, 'order-confirmation')).toBe(false);
      expect(shouldSendWebhook(undefined, 'order-confirmation')).toBe(false);
    });

    it('should return false when webhook is disabled', () => {
      const prefs = makePrefs({ webhook: { enabled: false } });
      expect(shouldSendWebhook(prefs, 'order-confirmation')).toBe(false);
    });

    it('should return true when webhook is enabled and category is subscribed', () => {
      const prefs = makePrefs({ webhook: { enabled: true } });
      expect(shouldSendWebhook(prefs, 'order-confirmation')).toBe(true);
      expect(shouldSendWebhook(prefs, 'welcome')).toBe(true);
    });

    it('should return false when category is not subscribed', () => {
      const prefs = makePrefs({ webhook: { enabled: true, subscribedCategories: ['order-updates'] } });
      expect(shouldSendWebhook(prefs, 'welcome')).toBe(false);
      expect(shouldSendWebhook(prefs, 'order-confirmation')).toBe(true);
    });
  });

  describe('shouldSendToChannel', () => {
    it('should dispatch to email check', () => {
      const prefs = makePrefs({ email: { enabled: false } });
      expect(shouldSendToChannel(prefs, 'email', 'order-confirmation')).toBe(false);
    });

    it('should dispatch to sms check', () => {
      const prefs = makePrefs({ sms: { enabled: true } });
      expect(shouldSendToChannel(prefs, 'sms', 'order-confirmation')).toBe(true);
    });

    it('should dispatch to webhook check', () => {
      const prefs = makePrefs({ webhook: { enabled: true } });
      expect(shouldSendToChannel(prefs, 'webhook', 'welcome')).toBe(true);
    });

    it('should allow unknown channels by default', () => {
      const prefs = makePrefs();
      expect(shouldSendToChannel(prefs, 'in-app', 'order-confirmation')).toBe(true);
    });

    it('should handle null preferences per channel default', () => {
      expect(shouldSendToChannel(null, 'email', 'order-confirmation')).toBe(true);
      expect(shouldSendToChannel(null, 'sms', 'order-confirmation')).toBe(false);
      expect(shouldSendToChannel(null, 'webhook', 'order-confirmation')).toBe(false);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
  });

  describe('getPreferences', () => {
    it('should return defaults when no preferences exist', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toContain('order-updates');
      expect(prefs.email.subscribedCategories).toContain('account');
      // SMS and webhook default to disabled
      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.subscribedCategories).toContain('order-updates');
      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.subscribedCategories).toContain('account');
    });

    it('should return stored preferences when they exist', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.enabled).toBe(false);
    });
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.id).toBe('prefs-user-1');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(['order-updates', 'account']);
      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.subscribedCategories).toEqual(['order-updates', 'account']);
      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.subscribedCategories).toEqual(['order-updates', 'account']);
    });

    it('should create preferences with custom email settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          frequency: 'daily-digest',
          subscribedCategories: ['order-updates'],
        },
      });

      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.email.subscribedCategories).toEqual(['order-updates']);
    });

    it('should create preferences with custom SMS settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        sms: {
          enabled: true,
          subscribedCategories: ['order-updates'],
        },
      });

      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.subscribedCategories).toEqual(['order-updates']);
    });

    it('should create preferences with custom webhook settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        webhook: {
          enabled: true,
          subscribedCategories: ['account'],
        },
      });

      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.subscribedCategories).toEqual(['account']);
    });

    it('should create preferences with all channels configured', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'daily-digest' },
        sms: { enabled: true },
        webhook: { enabled: true, subscribedCategories: ['order-updates'] },
      });

      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.subscribedCategories).toEqual(['order-updates']);
    });

    it('should merge partial email settings with defaults', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'weekly-digest' },
      });

      expect(prefs.email.enabled).toBe(true); // default
      expect(prefs.email.frequency).toBe('weekly-digest'); // overridden
      expect(prefs.email.subscribedCategories).toEqual(['order-updates', 'account']); // default
    });

    it('should throw if preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });
  });

  describe('updatePreferences', () => {
    it('should update email preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('immediate'); // unchanged
    });

    it('should update subscribed categories', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { subscribedCategories: ['order-updates'] },
      });

      expect(updated.email.subscribedCategories).toEqual(['order-updates']);
    });

    it('should update SMS preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        sms: { enabled: true },
      });

      expect(updated.sms.enabled).toBe(true);
      expect(updated.sms.subscribedCategories).toEqual(['order-updates', 'account']); // unchanged
    });

    it('should update webhook preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        webhook: { enabled: true, subscribedCategories: ['order-updates'] },
      });

      expect(updated.webhook.enabled).toBe(true);
      expect(updated.webhook.subscribedCategories).toEqual(['order-updates']);
    });

    it('should update multiple channels at once', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily-digest' },
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      expect(updated.email.frequency).toBe('daily-digest');
      expect(updated.sms.enabled).toBe(true);
      expect(updated.webhook.enabled).toBe(true);
    });

    it('should throw if no preferences exist', () => {
      expect(() =>
        service.updatePreferences('user-1', { email: { enabled: false } }),
      ).toThrow('No preferences found for user: user-1');
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      const result = service.deletePreferences('user-1');
      expect(result).toBe(true);

      // After delete, should get defaults
      const prefs = service.getPreferences('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.webhook.enabled).toBe(false);
    });

    it('should return false if no preferences exist', () => {
      const result = service.deletePreferences('user-1');
      expect(result).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (default behavior)', () => {
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'order-status-update')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'user-updated')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return false when frequency is none', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'none' },
      });

      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['account'] },
      });

      // order-confirmation maps to 'order-updates' category
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'order-status-update')).toBe(false);

      // welcome maps to 'account' category
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
    });

    it('should allow order-updates but block account notifications', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['order-updates'] },
      });

      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'user-updated')).toBe(false);
    });
  });

  describe('shouldSendToChannel', () => {
    it('should check email channel', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      expect(service.shouldSendToChannel('user-1', 'email', 'order-confirmation')).toBe(false);
    });

    it('should check sms channel (opt-in, default false)', () => {
      expect(service.shouldSendToChannel('user-1', 'sms', 'order-confirmation')).toBe(false);

      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true },
      });

      expect(service.shouldSendToChannel('user-1', 'sms', 'order-confirmation')).toBe(true);
    });

    it('should check webhook channel (opt-in, default false)', () => {
      expect(service.shouldSendToChannel('user-1', 'webhook', 'welcome')).toBe(false);

      service.createPreferences({
        userId: 'user-1',
        webhook: { enabled: true },
      });

      expect(service.shouldSendToChannel('user-1', 'webhook', 'welcome')).toBe(true);
    });

    it('should respect per-channel category subscriptions independently', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['order-updates'] },
        sms: { enabled: true, subscribedCategories: ['account'] },
      });

      // Email: order-updates only
      expect(service.shouldSendToChannel('user-1', 'email', 'order-confirmation')).toBe(true);
      expect(service.shouldSendToChannel('user-1', 'email', 'welcome')).toBe(false);

      // SMS: account only
      expect(service.shouldSendToChannel('user-1', 'sms', 'order-confirmation')).toBe(false);
      expect(service.shouldSendToChannel('user-1', 'sms', 'welcome')).toBe(true);
    });
  });
});

