        email: { frequency: 'none' },
      });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);
      expect(transport.getSentEmails()).toHaveLength(0);
    });
  });

  describe('multi-channel preferences', () => {
    let preferencesService: PreferencesService;
    let smsTransport: InMemorySmsTransport;

    beforeEach(() => {
      const db = new Database();
      const prefsRepo = new PreferencesRepository(db);
      preferencesService = new PreferencesService(prefsRepo);
      service.setPreferencesService(preferencesService);

      smsTransport = new InMemorySmsTransport();
      const smsAdapter = new SmsAdapter({
        transport: smsTransport,
        phoneNumberResolver: async (recipient) => {
          const phones: Record<string, string> = {
            'user-1': '+15551234567',
            'user-2': '+15559876543',
          };
          return phones[recipient] ?? null;
        },
      });
      service.registerAdapter(smsAdapter);
    });

    it('should suppress SMS when SMS preferences are not set (opt-in default)', async () => {
      // No preferences created — SMS defaults to disabled
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: 'user-1',
        userId: 'user-1',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });

      expect(smsTransport.getSentMessages()).toHaveLength(0);
    });

    it('should send SMS when user has opted in', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        sms: { enabled: true },
      });

      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: 'user-1',
        userId: 'user-1',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });

      expect(smsTransport.getSentMessages()).toHaveLength(1);
    });

    it('should suppress SMS when user has opted in but category not subscribed', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, subscribedCategories: ['account'] },
      });

      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: 'user-1',
        userId: 'user-1',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });

      expect(smsTransport.getSentMessages()).toHaveLength(0);
    });

    it('should allow email and suppress SMS independently', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true },
        sms: { enabled: false },
      });

      // Email should go through
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);
      expect(transport.getSentEmails()).toHaveLength(1);

      // SMS should be suppressed
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: 'user-1',
        userId: 'user-1',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });
      expect(smsTransport.getSentMessages()).toHaveLength(0);
    });

    it('should allow both email and SMS when both enabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true },
        sms: { enabled: true },
      });

      // Email
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);
      expect(transport.getSentEmails()).toHaveLength(1);

      // SMS
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: 'user-1',
        userId: 'user-1',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });
      expect(smsTransport.getSentMessages()).toHaveLength(1);
    });
  });
});

