 import type { NotificationType } from '../models/notification.js';
+import type { NotificationChannel } from '../models/notification.js';
 import type { UserPreferences, NotificationCategory } from '../models/user-preferences.js';
 import { notificationTypeToCategory } from '../models/user-preferences.js';

@@ -16,9 +19,6 @@ import { notificationTypeToCategory } from '../models/user-preferences.js';
  * - No preferences exist (null/undefined — default: send all)
  * - Email is enabled AND frequency is not 'none' AND the notification's
