@@ -44,3 +44,81 @@ export function shouldSendEmail(

   return true;
 }
+
+/**
+ * Determine whether an SMS notification should be sent based on user preferences.
+ *
+ * Returns true if:
+ * - No preferences exist (null/undefined — default: do NOT send, SMS is opt-in)
+ * - SMS is enabled AND the notification's category is in subscribed categories
+ */
+export function shouldSendSms(
+  prefs: UserPreferences | null | undefined,
+  notificationType: NotificationType,
+): boolean {
+  // No preferences stored — SMS defaults to disabled (opt-in)
+  if (!prefs) {
+    return false;
+  }
+
+  if (!prefs.sms.enabled) {
+    return false;
+  }
+
+  const category: NotificationCategory = notificationTypeToCategory[notificationType];
+  if (!prefs.sms.subscribedCategories.includes(category)) {
+    return false;
+  }
+
+  return true;
+}
+
+/**
+ * Determine whether a webhook notification should be sent based on user preferences.
+ *
+ * Returns true if:
+ * - No preferences exist (null/undefined — default: do NOT send, webhook is opt-in)
+ * - Webhook is enabled AND the notification's category is in subscribed categories
+ */
+export function shouldSendWebhook(
+  prefs: UserPreferences | null | undefined,
+  notificationType: NotificationType,
+): boolean {
+  // No preferences stored — webhook defaults to disabled (opt-in)
+  if (!prefs) {
+    return false;
+  }
+
+  if (!prefs.webhook.enabled) {
+    return false;
+  }
+
+  const category: NotificationCategory = notificationTypeToCategory[notificationType];
+  if (!prefs.webhook.subscribedCategories.includes(category)) {
+    return false;
+  }
+
+  return true;
+}
+
+/**
+ * Generic channel-based preference check.
+ * Dispatches to the appropriate per-channel function.
+ */
+export function shouldSendToChannel(
+  prefs: UserPreferences | null | undefined,
+  channel: NotificationChannel,
+  notificationType: NotificationType,
+): boolean {
+  switch (channel) {
+    case 'email':
+      return shouldSendEmail(prefs, notificationType);
+    case 'sms':
+      return shouldSendSms(prefs, notificationType);
+    case 'webhook':
+      return shouldSendWebhook(prefs, notificationType);
+    default:
+      // Channels without preference support (e.g. 'in-app') — allow by default
+      return true;
+  }
+}

